dfp_read_field_def_event_metadata(<<>>, 0, 0, _, F@_1, F@_2, F@_3, F@_4, _) -> #{timestamp_ns => F@_1, ingested_ns => F@_2, source => F@_3, trace_id => F@_4};
dfp_read_field_def_event_metadata(Other, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData) -> dg_read_field_def_event_metadata(Other, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData).

dg_read_field_def_event_metadata(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData) when N < 32 - 7 -> dg_read_field_def_event_metadata(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData);
dg_read_field_def_event_metadata(<<0:1, X:7, Rest/binary>>, N, Acc, _, F@_1, F@_2, F@_3, F@_4, TrUserData) ->
    Key = X bsl N + Acc,
    case Key of
        8 -> d_field_event_metadata_timestamp_ns(Rest, 0, 0, 0, F@_1, F@_2, F@_3, F@_4, TrUserData);
        16 -> d_field_event_metadata_ingested_ns(Rest, 0, 0, 0, F@_1, F@_2, F@_3, F@_4, TrUserData);
        24 -> d_field_event_metadata_source(Rest, 0, 0, 0, F@_1, F@_2, F@_3, F@_4, TrUserData);
        34 -> d_field_event_metadata_trace_id(Rest, 0, 0, 0, F@_1, F@_2, F@_3, F@_4, TrUserData);
        _ ->
            case Key band 7 of
                0 -> skip_varint_event_metadata(Rest, 0, 0, Key bsr 3, F@_1, F@_2, F@_3, F@_4, TrUserData);
                1 -> skip_64_event_metadata(Rest, 0, 0, Key bsr 3, F@_1, F@_2, F@_3, F@_4, TrUserData);
                2 -> skip_length_delimited_event_metadata(Rest, 0, 0, Key bsr 3, F@_1, F@_2, F@_3, F@_4, TrUserData);
                3 -> skip_group_event_metadata(Rest, 0, 0, Key bsr 3, F@_1, F@_2, F@_3, F@_4, TrUserData);
                5 -> skip_32_event_metadata(Rest, 0, 0, Key bsr 3, F@_1, F@_2, F@_3, F@_4, TrUserData)
            end
    end;
dg_read_field_def_event_metadata(<<>>, 0, 0, _, F@_1, F@_2, F@_3, F@_4, _) -> #{timestamp_ns => F@_1, ingested_ns => F@_2, source => F@_3, trace_id => F@_4}.

d_field_event_metadata_timestamp_ns(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData) when N < 57 -> d_field_event_metadata_timestamp_ns(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData);
d_field_event_metadata_timestamp_ns(<<0:1, X:7, Rest/binary>>, N, Acc, F, _, F@_2, F@_3, F@_4, TrUserData) ->
    {NewFValue, RestF} = {begin <<Res:64/signed-native>> = <<(X bsl N + Acc):64/unsigned-native>>, id(Res, TrUserData) end, Rest},
    dfp_read_field_def_event_metadata(RestF, 0, 0, F, NewFValue, F@_2, F@_3, F@_4, TrUserData).

d_field_event_metadata_ingested_ns(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData) when N < 57 -> d_field_event_metadata_ingested_ns(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData);
d_field_event_metadata_ingested_ns(<<0:1, X:7, Rest/binary>>, N, Acc, F, F@_1, _, F@_3, F@_4, TrUserData) ->
    {NewFValue, RestF} = {begin <<Res:64/signed-native>> = <<(X bsl N + Acc):64/unsigned-native>>, id(Res, TrUserData) end, Rest},
    dfp_read_field_def_event_metadata(RestF, 0, 0, F, F@_1, NewFValue, F@_3, F@_4, TrUserData).

d_field_event_metadata_source(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData) when N < 57 -> d_field_event_metadata_source(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData);
d_field_event_metadata_source(<<0:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, _, F@_4, TrUserData) ->
    {NewFValue, RestF} = {id(d_enum_Source(begin <<Res:32/signed-native>> = <<(X bsl N + Acc):32/unsigned-native>>, id(Res, TrUserData) end), TrUserData), Rest},
    dfp_read_field_def_event_metadata(RestF, 0, 0, F, F@_1, F@_2, NewFValue, F@_4, TrUserData).

d_field_event_metadata_trace_id(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData) when N < 57 -> d_field_event_metadata_trace_id(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData);
d_field_event_metadata_trace_id(<<0:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, _, TrUserData) ->
    {NewFValue, RestF} = begin Len = X bsl N + Acc, <<Utf8:Len/binary, Rest2/binary>> = Rest, {id(unicode:characters_to_list(Utf8, unicode), TrUserData), Rest2} end,
    dfp_read_field_def_event_metadata(RestF, 0, 0, F, F@_1, F@_2, F@_3, NewFValue, TrUserData).

skip_varint_event_metadata(<<1:1, _:7, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData) -> skip_varint_event_metadata(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData);
skip_varint_event_metadata(<<0:1, _:7, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData) -> dfp_read_field_def_event_metadata(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData).

skip_length_delimited_event_metadata(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData) when N < 57 -> skip_length_delimited_event_metadata(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData);
skip_length_delimited_event_metadata(<<0:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, TrUserData) ->
    Length = X bsl N + Acc,
    <<_:Length/binary, Rest2/binary>> = Rest,
    dfp_read_field_def_event_metadata(Rest2, 0, 0, F, F@_1, F@_2, F@_3, F@_4, TrUserData).

skip_group_event_metadata(Bin, _, Z2, FNum, F@_1, F@_2, F@_3, F@_4, TrUserData) ->
    {_, Rest} = read_group(Bin, FNum),
    dfp_read_field_def_event_metadata(Rest, 0, Z2, FNum, F@_1, F@_2, F@_3, F@_4, TrUserData).

skip_32_event_metadata(<<_:32, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData) -> dfp_read_field_def_event_metadata(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData).

skip_64_event_metadata(<<_:64, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData) -> dfp_read_field_def_event_metadata(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, TrUserData).

d_enum_GamePhase(0) -> 'GAME_PHASE_UNSPECIFIED';
d_enum_GamePhase(1) -> 'GAME_PHASE_PRE_GAME';
d_enum_GamePhase(2) -> 'GAME_PHASE_IN_PROGRESS';
d_enum_GamePhase(3) -> 'GAME_PHASE_HALFTIME';
d_enum_GamePhase(4) -> 'GAME_PHASE_QUARTER_BREAK';
d_enum_GamePhase(5) -> 'GAME_PHASE_FINAL';
d_enum_GamePhase(V) -> V.

d_enum_Source(0) -> 'SOURCE_UNSPECIFIED';
d_enum_Source(1) -> 'SOURCE_POLYMARKET_WS';
d_enum_Source(2) -> 'SOURCE_POLYMARKET_REST';
d_enum_Source(3) -> 'SOURCE_NBA_API';
d_enum_Source(4) -> 'SOURCE_ESPN';
d_enum_Source(5) -> 'SOURCE_SIMULATOR_REPLAY';
d_enum_Source(6) -> 'SOURCE_SIMULATOR_SYNTHETIC';
d_enum_Source(V) -> V.

read_group(Bin, FieldNum) ->
    {NumBytes, EndTagLen} = read_gr_b(Bin, 0, 0, 0, 0, FieldNum),
    <<Group:NumBytes/binary, _:EndTagLen/binary, Rest/binary>> = Bin,
    {Group, Rest}.

%% Like skipping over fields, but record the total length,
%% Each field is <(FieldNum bsl 3) bor FieldType> ++ <FieldValue>
%% Record the length because varints may be non-optimally encoded.
%%
%% Groups can be nested, but assume the same FieldNum cannot be nested
%% because group field numbers are shared with the rest of the fields
%% numbers. Thus we can search just for an group-end with the same
%% field number.
%%
%% (The only time the same group field number could occur would
%% be in a nested sub message, but then it would be inside a
%% length-delimited entry, which we skip-read by length.)
read_gr_b(<<1:1, X:7, Tl/binary>>, N, Acc, NumBytes, TagLen, FieldNum)
  when N < (32-7) ->
    read_gr_b(Tl, N+7, X bsl N + Acc, NumBytes, TagLen+1, FieldNum);
read_gr_b(<<0:1, X:7, Tl/binary>>, N, Acc, NumBytes, TagLen,
          FieldNum) ->
    Key = X bsl N + Acc,
    TagLen1 = TagLen + 1,
    case {Key bsr 3, Key band 7} of
        {FieldNum, 4} -> % 4 = group_end
            {NumBytes, TagLen1};
        {_, 0} -> % 0 = varint
            read_gr_vi(Tl, 0, NumBytes + TagLen1, FieldNum);
        {_, 1} -> % 1 = bits64
            <<_:64, Tl2/binary>> = Tl,
            read_gr_b(Tl2, 0, 0, NumBytes + TagLen1 + 8, 0, FieldNum);
        {_, 2} -> % 2 = length_delimited
            read_gr_ld(Tl, 0, 0, NumBytes + TagLen1, FieldNum);
        {_, 3} -> % 3 = group_start
            read_gr_b(Tl, 0, 0, NumBytes + TagLen1, 0, FieldNum);
        {_, 4} -> % 4 = group_end
            read_gr_b(Tl, 0, 0, NumBytes + TagLen1, 0, FieldNum);
        {_, 5} -> % 5 = bits32
            <<_:32, Tl2/binary>> = Tl,
            read_gr_b(Tl2, 0, 0, NumBytes + TagLen1 + 4, 0, FieldNum)
    end.

read_gr_vi(<<1:1, _:7, Tl/binary>>, N, NumBytes, FieldNum)
  when N < (64-7) ->
    read_gr_vi(Tl, N+7, NumBytes+1, FieldNum);
read_gr_vi(<<0:1, _:7, Tl/binary>>, _, NumBytes, FieldNum) ->
    read_gr_b(Tl, 0, 0, NumBytes+1, 0, FieldNum).

read_gr_ld(<<1:1, X:7, Tl/binary>>, N, Acc, NumBytes, FieldNum)
  when N < (64-7) ->
    read_gr_ld(Tl, N+7, X bsl N + Acc, NumBytes+1, FieldNum);
read_gr_ld(<<0:1, X:7, Tl/binary>>, N, Acc, NumBytes, FieldNum) ->
    Len = X bsl N + Acc,
    NumBytes1 = NumBytes + 1,
    <<_:Len/binary, Tl2/binary>> = Tl,
    read_gr_b(Tl2, 0, 0, NumBytes1 + Len, 0, FieldNum).

merge_msgs(Prev, New, MsgName) when is_atom(MsgName) -> merge_msgs(Prev, New, MsgName, []).

merge_msgs(Prev, New, MsgName, Opts) ->
    TrUserData = proplists:get_value(user_data, Opts),
    case MsgName of
        game_event -> merge_msg_game_event(Prev, New, TrUserData);
        event_metadata -> merge_msg_event_metadata(Prev, New, TrUserData)
    end.

-compile({nowarn_unused_function,merge_msg_game_event/3}).
merge_msg_game_event(PMsg, NMsg, TrUserData) ->
    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {#{meta := PFmeta}, #{meta := NFmeta}} -> S1#{meta => merge_msg_event_metadata(PFmeta, NFmeta, TrUserData)};
             {_, #{meta := NFmeta}} -> S1#{meta => NFmeta};
             {#{meta := PFmeta}, _} -> S1#{meta => PFmeta};
             {_, _} -> S1
         end,
    S3 = case {PMsg, NMsg} of
             {_, #{game_id := NFgame_id}} -> S2#{game_id => NFgame_id};
             {#{game_id := PFgame_id}, _} -> S2#{game_id => PFgame_id};
             _ -> S2
         end,
    S4 = case {PMsg, NMsg} of
             {_, #{home_team := NFhome_team}} -> S3#{home_team => NFhome_team};
             {#{home_team := PFhome_team}, _} -> S3#{home_team => PFhome_team};
             _ -> S3
         end,
    S5 = case {PMsg, NMsg} of
             {_, #{away_team := NFaway_team}} -> S4#{away_team => NFaway_team};
             {#{away_team := PFaway_team}, _} -> S4#{away_team => PFaway_team};
             _ -> S4
         end,
    S6 = case {PMsg, NMsg} of
             {_, #{home_score := NFhome_score}} -> S5#{home_score => NFhome_score};
             {#{home_score := PFhome_score}, _} -> S5#{home_score => PFhome_score};
             _ -> S5
         end,
    S7 = case {PMsg, NMsg} of
             {_, #{away_score := NFaway_score}} -> S6#{away_score => NFaway_score};
             {#{away_score := PFaway_score}, _} -> S6#{away_score => PFaway_score};
             _ -> S6
         end,
    S8 = case {PMsg, NMsg} of
             {_, #{period := NFperiod}} -> S7#{period => NFperiod};
             {#{period := PFperiod}, _} -> S7#{period => PFperiod};
             _ -> S7
         end,
    S9 = case {PMsg, NMsg} of
             {_, #{game_clock_ms := NFgame_clock_ms}} -> S8#{game_clock_ms => NFgame_clock_ms};
             {#{game_clock_ms := PFgame_clock_ms}, _} -> S8#{game_clock_ms => PFgame_clock_ms};
             _ -> S8
         end,
    S10 = case {PMsg, NMsg} of
              {_, #{phase := NFphase}} -> S9#{phase => NFphase};
              {#{phase := PFphase}, _} -> S9#{phase => PFphase};
              _ -> S9
          end,
    case {PMsg, NMsg} of
        {_, #{possession_team := NFpossession_team}} -> S10#{possession_team => NFpossession_team};
        {#{possession_team := PFpossession_team}, _} -> S10#{possession_team => PFpossession_team};
        _ -> S10
    end.

-compile({nowarn_unused_function,merge_msg_event_metadata/3}).
merge_msg_event_metadata(PMsg, NMsg, _) ->
    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {_, #{timestamp_ns := NFtimestamp_ns}} -> S1#{timestamp_ns => NFtimestamp_ns};
             {#{timestamp_ns := PFtimestamp_ns}, _} -> S1#{timestamp_ns => PFtimestamp_ns};
             _ -> S1
         end,
    S3 = case {PMsg, NMsg} of
             {_, #{ingested_ns := NFingested_ns}} -> S2#{ingested_ns => NFingested_ns};
             {#{ingested_ns := PFingested_ns}, _} -> S2#{ingested_ns => PFingested_ns};
             _ -> S2
         end,
    S4 = case {PMsg, NMsg} of
             {_, #{source := NFsource}} -> S3#{source => NFsource};
             {#{source := PFsource}, _} -> S3#{source => PFsource};
             _ -> S3
         end,
    case {PMsg, NMsg} of
        {_, #{trace_id := NFtrace_id}} -> S4#{trace_id => NFtrace_id};
        {#{trace_id := PFtrace_id}, _} -> S4#{trace_id => PFtrace_id};
        _ -> S4
    end.


verify_msg(Msg, MsgName) when is_atom(MsgName) -> verify_msg(Msg, MsgName, []).

verify_msg(Msg, MsgName, Opts) ->
    TrUserData = proplists:get_value(user_data, Opts),
    case MsgName of
        game_event -> v_msg_game_event(Msg, [MsgName], TrUserData);
        event_metadata -> v_msg_event_metadata(Msg, [MsgName], TrUserData);
        _ -> mk_type_error(not_a_known_message, Msg, [])
    end.


-compile({nowarn_unused_function,v_msg_game_event/3}).
-dialyzer({nowarn_function,v_msg_game_event/3}).
v_msg_game_event(#{} = M, Path, TrUserData) ->
    case M of
        #{meta := F1} -> v_submsg_event_metadata(F1, [meta | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{game_id := F2} -> v_type_string(F2, [game_id | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{home_team := F3} -> v_type_string(F3, [home_team | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{away_team := F4} -> v_type_string(F4, [away_team | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{home_score := F5} -> v_type_int32(F5, [home_score | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{away_score := F6} -> v_type_int32(F6, [away_score | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{period := F7} -> v_type_int32(F7, [period | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{game_clock_ms := F8} -> v_type_int32(F8, [game_clock_ms | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{phase := F9} -> v_enum_GamePhase(F9, [phase | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{possession_team := F10} -> v_type_string(F10, [possession_team | Path], TrUserData);
        _ -> ok
    end,
    lists:foreach(fun (meta) -> ok;
                      (game_id) -> ok;
                      (home_team) -> ok;
                      (away_team) -> ok;
                      (home_score) -> ok;
                      (away_score) -> ok;
                      (period) -> ok;
                      (game_clock_ms) -> ok;
                      (phase) -> ok;
                      (possession_team) -> ok;
                      (OtherKey) -> mk_type_error({extraneous_key, OtherKey}, M, Path)
                  end,
                  maps:keys(M)),
    ok;
v_msg_game_event(M, Path, _TrUserData) when is_map(M) -> mk_type_error({missing_fields, [] -- maps:keys(M), game_event}, M, Path);
v_msg_game_event(X, Path, _TrUserData) -> mk_type_error({expected_msg, game_event}, X, Path).

-compile({nowarn_unused_function,v_submsg_event_metadata/3}).
-dialyzer({nowarn_function,v_submsg_event_metadata/3}).
v_submsg_event_metadata(Msg, Path, TrUserData) -> v_msg_event_metadata(Msg, Path, TrUserData).

-compile({nowarn_unused_function,v_msg_event_metadata/3}).
-dialyzer({nowarn_function,v_msg_event_metadata/3}).
v_msg_event_metadata(#{} = M, Path, TrUserData) ->
    case M of
        #{timestamp_ns := F1} -> v_type_int64(F1, [timestamp_ns | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{ingested_ns := F2} -> v_type_int64(F2, [ingested_ns | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{source := F3} -> v_enum_Source(F3, [source | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{trace_id := F4} -> v_type_string(F4, [trace_id | Path], TrUserData);
        _ -> ok
    end,
    lists:foreach(fun (timestamp_ns) -> ok;
                      (ingested_ns) -> ok;
                      (source) -> ok;
                      (trace_id) -> ok;
                      (OtherKey) -> mk_type_error({extraneous_key, OtherKey}, M, Path)
                  end,
                  maps:keys(M)),
    ok;
v_msg_event_metadata(M, Path, _TrUserData) when is_map(M) -> mk_type_error({missing_fields, [] -- maps:keys(M), event_metadata}, M, Path);
v_msg_event_metadata(X, Path, _TrUserData) -> mk_type_error({expected_msg, event_metadata}, X, Path).

-compile({nowarn_unused_function,v_enum_GamePhase/3}).
-dialyzer({nowarn_function,v_enum_GamePhase/3}).
v_enum_GamePhase('GAME_PHASE_UNSPECIFIED', _Path, _TrUserData) -> ok;
v_enum_GamePhase('GAME_PHASE_PRE_GAME', _Path, _TrUserData) -> ok;
v_enum_GamePhase('GAME_PHASE_IN_PROGRESS', _Path, _TrUserData) -> ok;
v_enum_GamePhase('GAME_PHASE_HALFTIME', _Path, _TrUserData) -> ok;
v_enum_GamePhase('GAME_PHASE_QUARTER_BREAK', _Path, _TrUserData) -> ok;
v_enum_GamePhase('GAME_PHASE_FINAL', _Path, _TrUserData) -> ok;
v_enum_GamePhase(V, _Path, _TrUserData) when -2147483648 =< V, V =< 2147483647, is_integer(V) -> ok;
v_enum_GamePhase(X, Path, _TrUserData) -> mk_type_error({invalid_enum, 'GamePhase'}, X, Path).

-compile({nowarn_unused_function,v_enum_Source/3}).
-dialyzer({nowarn_function,v_enum_Source/3}).
v_enum_Source('SOURCE_UNSPECIFIED', _Path, _TrUserData) -> ok;
v_enum_Source('SOURCE_POLYMARKET_WS', _Path, _TrUserData) -> ok;
v_enum_Source('SOURCE_POLYMARKET_REST', _Path, _TrUserData) -> ok;
v_enum_Source('SOURCE_NBA_API', _Path, _TrUserData) -> ok;
v_enum_Source('SOURCE_ESPN', _Path, _TrUserData) -> ok;
v_enum_Source('SOURCE_SIMULATOR_REPLAY', _Path, _TrUserData) -> ok;
v_enum_Source('SOURCE_SIMULATOR_SYNTHETIC', _Path, _TrUserData) -> ok;
v_enum_Source(V, _Path, _TrUserData) when -2147483648 =< V, V =< 2147483647, is_integer(V) -> ok;
v_enum_Source(X, Path, _TrUserData) -> mk_type_error({invalid_enum, 'Source'}, X, Path).

-compile({nowarn_unused_function,v_type_int32/3}).
-dialyzer({nowarn_function,v_type_int32/3}).
v_type_int32(N, _Path, _TrUserData) when is_integer(N), -2147483648 =< N, N =< 2147483647 -> ok;
v_type_int32(N, Path, _TrUserData) when is_integer(N) -> mk_type_error({value_out_of_range, int32, signed, 32}, N, Path);
v_type_int32(X, Path, _TrUserData) -> mk_type_error({bad_integer, int32, signed, 32}, X, Path).

-compile({nowarn_unused_function,v_type_int64/3}).
-dialyzer({nowarn_function,v_type_int64/3}).
v_type_int64(N, _Path, _TrUserData) when is_integer(N), -9223372036854775808 =< N, N =< 9223372036854775807 -> ok;
v_type_int64(N, Path, _TrUserData) when is_integer(N) -> mk_type_error({value_out_of_range, int64, signed, 64}, N, Path);
v_type_int64(X, Path, _TrUserData) -> mk_type_error({bad_integer, int64, signed, 64}, X, Path).

-compile({nowarn_unused_function,v_type_string/3}).
-dialyzer({nowarn_function,v_type_string/3}).
v_type_string(S, Path, _TrUserData) when is_list(S); is_binary(S) ->
    try unicode:characters_to_binary(S) of
        B when is_binary(B) -> ok;
        {error, _, _} -> mk_type_error(bad_unicode_string, S, Path)
    catch
        error:badarg -> mk_type_error(bad_unicode_string, S, Path)
    end;
v_type_string(X, Path, _TrUserData) -> mk_type_error(bad_unicode_string, X, Path).

-compile({nowarn_unused_function,mk_type_error/3}).
-spec mk_type_error(_, _, list()) -> no_return().
mk_type_error(Error, ValueSeen, Path) ->
    Path2 = prettify_path(Path),
    erlang:error({gpb_type_error, {Error, [{value, ValueSeen}, {path, Path2}]}}).


-compile({nowarn_unused_function,prettify_path/1}).
-dialyzer({nowarn_function,prettify_path/1}).
prettify_path([]) -> top_level;
prettify_path(PathR) -> lists:append(lists:join(".", lists:map(fun atom_to_list/1, lists:reverse(PathR)))).


-compile({nowarn_unused_function,id/2}).
-compile({inline,id/2}).
id(X, _TrUserData) -> X.

-compile({nowarn_unused_function,v_ok/3}).
-compile({inline,v_ok/3}).
v_ok(_Value, _Path, _TrUserData) -> ok.

-compile({nowarn_unused_function,m_overwrite/3}).
-compile({inline,m_overwrite/3}).
m_overwrite(_Prev, New, _TrUserData) -> New.

-compile({nowarn_unused_function,cons/3}).
-compile({inline,cons/3}).
cons(Elem, Acc, _TrUserData) -> [Elem | Acc].

-compile({nowarn_unused_function,lists_reverse/2}).
-compile({inline,lists_reverse/2}).
'lists_reverse'(L, _TrUserData) -> lists:reverse(L).
-compile({nowarn_unused_function,'erlang_++'/3}).
-compile({inline,'erlang_++'/3}).
'erlang_++'(A, B, _TrUserData) -> A ++ B.


